<template><el-card shadow="never"><div class="toolbar"><el-button type="primary" @click="openCreate">新增账号</el-button></div><el-table :data="rows" border><el-table-column prop="username" label="登录账号"/><el-table-column prop="displayName" label="显示名称"/><el-table-column label="状态" width="100"><template #default="{row}"><el-tag :type="row.status===1?'success':'info'">{{row.status===1?'启用':'停用'}}</el-tag></template></el-table-column><el-table-column prop="lastLoginAt" label="最后登录"/><el-table-column label="操作" width="120"><template #default="{row}"><el-button link type="warning" @click="reset(row)">重置密码</el-button></template></el-table-column></el-table><el-dialog v-model="visible" title="新增登录账号" width="520px"><el-form label-width="100px"><el-form-item label="登录账号"><el-input v-model="form.username"/></el-form-item><el-form-item label="显示名称"><el-input v-model="form.displayName"/></el-form-item><el-form-item label="临时密码"><el-input v-model="form.temporaryPassword" type="password" show-password/></el-form-item><el-form-item label="角色"><el-select v-model="form.roles" multiple><el-option label="管理员" value="ADMIN"/><el-option label="操作员" value="OPERATOR"/><el-option label="只读" value="VIEWER"/></el-select></el-form-item></el-form><template #footer><el-button @click="visible=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></el-card></template>
<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{createAccount,listAccounts,resetAccountPassword}from'@/api';const rows=ref<any[]>([]),visible=ref(false),form=reactive({username:'',displayName:'',temporaryPassword:'',status:1,roles:['VIEWER']});async function load(){const r=await listAccounts({page:1,size:100});rows.value=r.data.data.records}function openCreate(){Object.assign(form,{username:'',displayName:'',temporaryPassword:'',status:1,roles:['VIEWER']});visible.value=true}async function save(){await createAccount(form);visible.value=false;ElMessage.success('账号已创建，首次登录必须修改密码');load()}async function reset(row:any){const{value}=await ElMessageBox.prompt('请输入新的临时密码','重置密码',{inputType:'password'});await resetAccountPassword(row.id,value);ElMessage.success('已重置，原会话将失效')}onMounted(load)</script>
<style scoped>.toolbar{margin-bottom:16px}</style>